import{_ as t,a as o,b as a,c as d,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as i}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as s,o as c,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Other/ocr.md","filePath":"ta/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"ta/Other/ocr.md"};function u(g,e,h,m,b,y){return c(),n("div",null,[...e[0]||(e[0]=[l('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR images, scans, document screenshots-இல் இருந்து text extract செய்கிறது.</p><p>recognition பிறகு result copy செய்யலாம், <code>Markdown</code>, <code>PDF</code>, <code>Word</code> ஆக export செய்யலாம், அல்லது பல formats ஒன்றாக package செய்து download செய்யலாம்.</p><h2 id="ocr-என்ன-செய்ய-முடியும்" tabindex="-1">OCR என்ன செய்ய முடியும் <a class="header-anchor" href="#ocr-என்ன-செய்ய-முடியும்" aria-label="Permalink to &quot;OCR என்ன செய்ய முடியும்&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Image text recognition</td><td>images, screenshots, scans-இல் இருந்து text extract.</td></tr><tr><td>Document layout recognition</td><td>tables, formulas, stamps, mixed text-image layouts-க்கு சிறந்தது.</td></tr><tr><td>Multiple services</td><td>Baidu PaddleOCR, Microsoft Azure Vision, Google Vision support.</td></tr><tr><td>Copy results</td><td>processing பிறகு recognized text copy.</td></tr><tr><td>Export files</td><td><code>Markdown</code>, <code>PDF</code>, <code>Word</code> export.</td></tr><tr><td>Batch packaging</td><td>பல files recognize செய்த பிறகு results package download.</td></tr></tbody></table><h2 id="முதலில்-ocr-services-configure-செய்யவும்" tabindex="-1">முதலில் OCR Services Configure செய்யவும் <a class="header-anchor" href="#முதலில்-ocr-services-configure-செய்யவும்" aria-label="Permalink to &quot;முதலில் OCR Services Configure செய்யவும்&quot;">​</a></h2><p>திறக்கவும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+t+'" alt="IP geolocation and OCR" loading="lazy"></p><p>பயன்படுத்த வேண்டிய services-க்கு credentials நிரப்பவும்:</p><table tabindex="0"><thead><tr><th>Service</th><th>What To Enter</th><th>Best For</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>முதலில் பரிந்துரை. documents, images, tables, mixed layouts.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> மற்றும் <code>Azure Vision API Key</code></td><td>Microsoft cloud services ஏற்கனவே பயன்படுத்தினால் useful.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. Service account <code>JSON</code> quota query-க்கு மட்டும்.</td><td>Google Cloud services பயன்படுத்தினால் useful.</td></tr></tbody></table><p>credentials நிரப்பிய பிறகு save செய்யவும்.</p><p>initial testing-க்கு ஒரு service போதும். மூன்றையும் configure செய்ய வேண்டியதில்லை.</p><h2 id="google-vision-setup" tabindex="-1">Google Vision Setup <a class="header-anchor" href="#google-vision-setup" aria-label="Permalink to &quot;Google Vision Setup&quot;">​</a></h2><p>Google setup இரண்டு பகுதிகள்:</p><table tabindex="0"><thead><tr><th>Goal</th><th>Requirement</th></tr></thead><tbody><tr><td>OCR பயன்படுத்த</td><td><code>Cloud Vision API</code> enable செய்து <code>API Key</code> உருவாக்கவும்.</td></tr><tr><td>usage query</td><td>service account உருவாக்கி <code>Monitoring Viewer</code> grant செய்து service account <code>JSON</code> download செய்யவும்.</td></tr></tbody></table><p><img src="'+i+'" alt="Google API key and service account" loading="lazy"></p><h3 id="google-ஐ-ocr-க்கு-பயன்படுத்துவது" tabindex="-1">Google-ஐ OCR-க்கு பயன்படுத்துவது <a class="header-anchor" href="#google-ஐ-ocr-க்கு-பயன்படுத்துவது" aria-label="Permalink to &quot;Google-ஐ OCR-க்கு பயன்படுத்துவது&quot;">​</a></h3><ol><li>Google Cloud Console திறக்கவும்.</li><li><code>APIs &amp; Services</code> செல்லவும்.</li><li><code>Library</code> திறந்து <code>Cloud Vision API</code> தேடி enable செய்யவும்.</li><li><code>Credentials</code>-க்கு திரும்பவும்.</li><li><code>API Key</code> உருவாக்கவும்.</li><li>API Key திறந்து copy செய்யவும்.</li><li>ImgBed <code>Google Vision API Key</code>-ல் paste செய்யவும்.</li><li>Save செய்யவும்.</li></ol><p>பிறகு OCR dialog-ல் Google Vision தேர்வு செய்யலாம்.</p><h3 id="google-usage-query" tabindex="-1">Google Usage Query <a class="header-anchor" href="#google-usage-query" aria-label="Permalink to &quot;Google Usage Query&quot;">​</a></h3><p>Quota query recognition-க்கு required அல்ல.</p><p>இது கடந்த 30 நாட்களில் Google Vision calls எவ்வளவு பயன்படுத்தப்பட்டது என rough count காட்டும்.</p><ol><li>Google Cloud Console-ல் <code>IAM &amp; Admin</code> திறக்கவும்.</li><li><code>Service Accounts</code> திறக்கவும்.</li><li>service account உருவாக்கவும், உதா. <code>vision-monitor</code>.</li><li><code>Monitoring Viewer</code> role கொடுக்கவும்.</li><li>service account details திறந்து key உருவாக்கவும்.</li><li><code>JSON</code> தேர்வு செய்யவும்.</li><li>generated JSON file download செய்யவும்.</li><li>ImgBed-க்கு திரும்பி service account <code>JSON</code> கீழ் import செய்யவும் (optional).</li><li>import success ஆன பிறகு quota query கிளிக் செய்யவும்.</li></ol><p>import பிறகு ImgBed service account-ன் project name காட்டும். usage query செய்யும்போது ImgBed Google monitoring data படித்து இந்த month&#39;s call count காட்டும்.</p><p>சுருக்கமாக:</p><table tabindex="0"><thead><tr><th>Item</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>OCR recognition செய்யும்.</td></tr><tr><td>Service account <code>JSON</code></td><td>Google Vision calls usage query.</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>service account usage data படிக்க அனுமதி.</td></tr></tbody></table><h2 id="baidu-paddleocr-token-பெறுதல்" tabindex="-1">Baidu PaddleOCR Token பெறுதல் <a class="header-anchor" href="#baidu-paddleocr-token-பெறுதல்" aria-label="Permalink to &quot;Baidu PaddleOCR Token பெறுதல்&quot;">​</a></h2><p>Baidu PaddleOCR access token தேவை.</p><p><img src="'+o+'" alt="Get PaddleOCR token" loading="lazy"></p><p>Baidu PaddleOCR page-ல் <code>API</code> call window திறந்து token பெற கிளிக் செய்து copy செய்யவும்.</p><p>ImgBed-க்கு திரும்பி <code>PaddleOCR Token</code>-ல் paste செய்து save செய்யவும்.</p><h2 id="recognition-தொடங்குதல்" tabindex="-1">Recognition தொடங்குதல் <a class="header-anchor" href="#recognition-தொடங்குதல்" aria-label="Permalink to &quot;Recognition தொடங்குதல்&quot;">​</a></h2><p>File Management-ல் image அல்லது document screenshot தேர்வு செய்து <code>OCR</code> கிளிக் செய்யவும்.</p><p><img src="'+a+'" alt="OCR recognition" loading="lazy"></p><p>dialog-ல் recognition service மற்றும் model தேர்வு செய்யவும்.</p><p>Common PaddleOCR model choices:</p><table tabindex="0"><thead><tr><th>Model</th><th>Best For</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>recommended default. documents, tables, formulas, stamps, mixed layouts.</td></tr><tr><td><code>PP-OCRv5</code></td><td>simple images, ordinary text, lightweight recognition.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>multilingual, complex images, chart-like content.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>complex document pages மற்றும் layout recovery.</td></tr></tbody></table><p>நிச்சயமில்லையெனில் <code>PP-StructureV3</code>-இல் தொடங்கவும்.</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Orientation correction</td><td>image rotated அல்லது skewed என்றால்.</td></tr><tr><td>Document flattening</td><td>photographed documents-ல் curvature அல்லது tilt இருந்தால்.</td></tr><tr><td>Layout detection</td><td>headings, paragraphs, tables, image structure preserve செய்ய.</td></tr><tr><td>Chart recognition</td><td>image-ல் charts அல்லது complex structures இருந்தால்.</td></tr><tr><td>Beautify <code>Markdown</code></td><td>exported Markdown readable ஆகும்.</td></tr></tbody></table><p>regular screenshots-க்கு minimal options வைத்திருக்கவும். document scans-க்கு document-related options enable செய்யவும்.</p><h2 id="results-பார்க்க" tabindex="-1">Results பார்க்க <a class="header-anchor" href="#results-பார்க்க" aria-label="Permalink to &quot;Results பார்க்க&quot;">​</a></h2><p>recognition முடிந்ததும் dialog result காட்டும்.</p><p>அதை நேரடியாக copy செய்யலாம் அல்லது export formats தேர்வு செய்யலாம்.</p><p><img src="'+d+'" alt="PDF recognition" loading="lazy"></p><p>document pages-க்கு exported <code>PDF</code> page appearance preserve செய்து text searchable ஆக வைத்திருக்கலாம். scans archive செய்யவும் பின்னர் content தேடவும் useful.</p><h2 id="export-format-தேர்வு" tabindex="-1">Export Format தேர்வு <a class="header-anchor" href="#export-format-தேர்வு" aria-label="Permalink to &quot;Export Format தேர்வு&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Best For</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>notes, documentation systems, later editing.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>page appearance மற்றும் scanned document results preserve.</td></tr><tr><td><code>Word (.docx)</code></td><td>layout editing, text modification, handoff.</td></tr><tr><td>Export all</td><td>multiple formats மற்றும் original image சேமிக்க, important archives.</td></tr></tbody></table><p>text மட்டும் வேண்டுமெனில் Markdown export செய்யவும்.</p><p>page appearance தேவை என்றால் PDF அல்லது Word.</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>exported Word documents office software-ல் open/edit செய்யலாம்.</p><p><img src="'+r+`" alt="Word result" loading="lazy"></p><p>சில documents Word output-ல் recognized images, headings, paragraphs கொண்டிருக்கும்.</p><p>recognition quality original image clarity, model choice, document complexity ஆகியவற்றை சார்ந்தது.</p><h2 id="ocr-க்கு-சிறந்த-file-types" tabindex="-1">OCR-க்கு சிறந்த File Types <a class="header-anchor" href="#ocr-க்கு-சிறந்த-file-types" aria-label="Permalink to &quot;OCR-க்கு சிறந்த File Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File Type</th><th>Recommendation</th></tr></thead><tbody><tr><td>Clear screenshots</td><td>directly recognize.</td></tr><tr><td>Scans</td><td><code>PP-StructureV3</code> prefer.</td></tr><tr><td>Photographed documents</td><td>orientation correction மற்றும் document flattening enable.</td></tr><tr><td>Tables, formulas, stamps</td><td>structured models prefer.</td></tr><tr><td>Simple short text images</td><td><code>PP-OCRv5</code> பொதுவாக போதும்.</td></tr></tbody></table><p>clearer images மற்றும் straight text நல்ல results தரும்.</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Recognition fails</td><td>service token அல்லது key save ஆனதா பார்க்கவும்.</td></tr><tr><td>Recognition slow</td><td>complex documents மற்றும் large images நேரம் எடுக்கும்.</td></tr><tr><td>Table incomplete</td><td>structured model try செய்யவும்.</td></tr><tr><td>Text mistakes</td><td>blur, glare, skew errors அதிகரிக்கும். clearer image try செய்யவும்.</td></tr><tr><td>Word output பல images கொண்டுள்ளது</td><td>structured models சில recognized images preserve செய்யலாம். இது normal.</td></tr></tbody></table><h3 id="google-quota-query-fail" tabindex="-1">Google Quota Query Fail <a class="header-anchor" href="#google-quota-query-fail" aria-label="Permalink to &quot;Google Quota Query Fail&quot;">​</a></h3><p>சரிபார்க்கவும்:</p><ol><li>Service account <code>JSON</code> imported.</li><li>service account-க்கு <code>Monitoring Viewer</code> role உள்ளது.</li><li>project-க்கு <code>Cloud Vision API</code> enabled.</li></ol><p>OCR மட்டும் வேண்டும், usage query வேண்டாம் என்றால் service account JSON தவிர்த்து <code>Google Vision API Key</code> மட்டும் நிரப்பலாம்.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings திறக்கவும்</span></span>
<span class="line"><span>-&gt; Other Settings திறக்கவும்</span></span>
<span class="line"><span>-&gt; OCR service credentials நிரப்பவும்</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; File Management-க்கு திரும்பவும்</span></span>
<span class="line"><span>-&gt; file தேர்வு செய்து OCR கிளிக் செய்யவும்</span></span>
<span class="line"><span>-&gt; model தேர்வு செய்யவும்</span></span>
<span class="line"><span>-&gt; recognition முடியும் வரை காத்திருக்கவும்</span></span>
<span class="line"><span>-&gt; results copy அல்லது Markdown / PDF / Word export செய்யவும்</span></span></code></pre></div>`,67)])])}const C=s(p,[["render",u]]);export{v as __pageData,C as default};
